<template>
    <div class="task-list-container">
        <div class="section-header mb-1">
            <div class="section-title">Tasks Requiring Reassignment</div>
            <div class="filter-options">
                <button 
                    v-for="filter in filters"
                    :key="filter"
                    :class="['filter-btn', { active: activeFilter === filter }]"
                    @click="setFilter(filter)">
                    {{ filter }}
                </button>
            </div>
        </div>


              <div class="row" v-if="activeFilter !='FollowUps'">
                <div  class="col-sm-12 col-lg-12 col-md-12 col-xl-12">
                 <div class="col-sm-12 col-lg-12 col-md-12 col-xl-12 d-flex mb-3 bg-light py-2 ">
                      
                      <label class="form-check form-check-inline mr-4">
                           <div class="custom-control custom-checkbox custom-control-inline">
                               <input id="chkSelectAll" v-model="selectAll" type="checkbox" class="chkItems custom-control-input">
                               <label for="chkSelectAll" class="custom-control-label font-16 pt-1">Select All</label>
                           </div>
                    </label>    
                    <div class=" mr-auto">
                           <button @click="openReassignModal" class="btn btn-success just_round4">{{ $t('Assign') }}</button>
                    </div>

                
                        <div class="ml-2 pt-1">
                            <span class="priority-high colorboxsquare" style="background-color: none;"></span>
                            <span class="ml-2">High</span>
                        </div>
                        <div class="ml-2 pt-1">
                            <span class="priority-low colorboxsquare"></span>
                            <span class="ml-2">Low</span>
                        </div>
                        <div class="ml-2 pt-1">
                            <span class="priority-medium colorboxsquare"></span>
                            <span class="ml-2">Meduim</span>
                        </div>



                  </div>
                   
              </div>
             
            </div>
        
        
        
               <div class="tasks-grid">
            <div 
                v-for="task in filteredTasks"
                :key="task.id"
                class="task-card"
                :class="getPriorityClass(task.priority)"
                :data-task-id="task.id">
                <div class="task-header">
                        <label class="form-check form-check-inline"  v-if="activeFilter!='FollowUps'">
                           <div class="custom-control custom-checkbox custom-control-inline">
                               <input :id="'chkTask_' + task.id" :checked="isTaskSelected(task)" @change="toggleTaskSelection(task, $event)" type="checkbox" class="chkItems custom-control-input">
                               <label :for="'chkTask_' + task.id" class="custom-control-label font-16 pt-1"></label>
                           </div>
                        </label> 
                           <div class="task-title pt-1" :title="task.title">{{ TruncateStr(task.title,25) }}</div>
                          <div class="task-priority ml-auto" :class="getPriorityClass(task.priority)">
                           {{ task.priority }}
                       </div>
                    
                 </div>

                 <div class="task-info">
                       <div class="task-type">{{ task.type }}</div>
                     <div class="task-due" v-if="task.dueDate">
                         <i class="fa fa-clock"></i> Due: {{ formatDate(task.dueDate) }}
                     </div>
                     <div class="task-project" v-if="task.projectName">
                         <i class="fa fa-folder"></i> {{ task.projectName }}
                     </div>
                 </div>



                    
                
                <div class="task-actions">
                    <button class="btn btn-outline" @click="openReassignModal(task)">
                        Reassign
                    </button>
                    <button class="btn btn-primary" @click="viewDetails(task)">
                        View Details
                    </button>
                </div>
            </div>
            
            <div v-if="filteredTasks.length === 0" class="no-tasks">
                <i class="fa fa-inbox"></i>
                <p>No {{ activeFilter }} found</p>
            </div>
        </div>
      
    </div>
</template>

<script>
import moment from 'moment';
export default {
    name: 'ResourceImpactTaskList',
    props: {
        tasks: {
            type: Array,
            default: () => []
        },
        projects:{
            type: Array,
            default: () => [] 
        },
        followUp:{
            type: Array,
            default: () => [] 
        }
    },
    data() {
        return {
            projectid:0,
            selectedTasks:[],
            IsAssignedUserShow:false,
            activeFilter: 'All',
            filters: ['All', 'Projects', 'Tasks',  'Todos', 'FollowUps'],
            draggedTask: null
        };
    },
    computed: {
        filteredTasks() {
            if (this.activeFilter === 'All' || this.activeFilter === 'Todos') {
                // Return both tasks and projects combined
                const tasks = Array.isArray(this.tasks) ? this.tasks : [];
                const projects = (this.projects && Array.isArray(this.projects.items)) ? this.projects.items : [];
                return [...tasks, ...projects];
            }
            
            const filterMap = {
                'Projects': 'Project',
                'Tasks': 'Task',
                'Meetings': 'Meeting',
                'Todos': 'Todo',
                'FollowUps': 'FollowUp'
            };
            
            const type = filterMap[this.activeFilter];
            
            if (type === 'Task') {
                return Array.isArray(this.tasks) ? this.tasks.filter(task => task.type === type) : [];
            } else if (type === 'Project') {
                return (this.projects && Array.isArray(this.projects.items)) ? this.projects.items : [];
            } 
            else if (type === 'FollowUp') {
                return (this.followUp && Array.isArray(this.followUp)) ? this.followUp : [];
            }
            else {
                const tasks = Array.isArray(this.tasks) ? this.tasks.filter(task => task.type === type) : [];
                const projects = (this.projects && Array.isArray(this.projects.items)) 
                    ? this.projects.items.filter(project => project.type === type) 
                    : [];
                return [...tasks, ...projects];
            }
        },
        selectAll: {
            get() {
                if (this.filteredTasks.length === 0) return false;
                // Check if all filtered tasks are selected (by ID comparison)
                const selectedIds = this.selectedTasks.map(sel => sel.id);
                return this.filteredTasks.every(task => selectedIds.includes(task.id));
            },
            set(checked) {
                if (checked) {
                    // Add all filtered tasks that are not already selected
                    const selectedIds = this.selectedTasks.map(sel => sel.id);
                    const toAdd = this.filteredTasks.filter(
                        task => !selectedIds.includes(task.id)
                    );
                    this.selectedTasks = [...this.selectedTasks, ...toAdd];
                } else {
                    // Remove only the filtered tasks from selection (keep others)
                    const filteredIds = this.filteredTasks.map(task => task.id);
                    this.selectedTasks = this.selectedTasks.filter(
                        sel => !filteredIds.includes(sel.id)
                    );
                }
            }
        }
    },
    methods: {

        setFilter(filter) {
            this.activeFilter = filter;
        },
        getPriorityClass(priority) {
            const priorityMap = { 
                'High': 'priority-high',
                'Medium': 'priority-medium',
                'Low': 'priority-low'
            };
            return priorityMap[priority] || 'priority-medium';
        },
        formatDate(date) {
            if (!date) return '';
            return moment(date).format('MMM DD, YYYY');
        },
        // onDragStart(event, task) {
        //     this.draggedTask = task;
        //     event.dataTransfer.setData('text/plain', task.id);
        //     event.dataTransfer.effectAllowed = 'move';
        //     event.currentTarget.classList.add('dragging');
        //     this.$emit('drag-start', task);
        // },
        // onDragEnd(event) {
        //     event.currentTarget.classList.remove('dragging');
        //     this.draggedTask = null;
        //     this.$emit('drag-end');
        // },
        openReassignModal(task) {
            this.selectedTasks = this.selectedTasks.length == 0 ? [task] :  this.selectedTasks;
            this.$emit('reassign-task', this.selectedTasks);
        },
        viewDetails(task) {
            this.$emit('view-details', task);
        },
        TruncateStr(str, maxLength) {
            if (!str) return '';
            if (str.length <= maxLength) return str;
            return str.substring(0, maxLength) + '...';
        },
        isTaskSelected(task) {
            // Check if task is selected by comparing ID
            return this.selectedTasks.some(sel => sel.id === task.id);
        },
        toggleTaskSelection(task, event) {
            const isChecked = event.target.checked;
            if (isChecked) {
                // Add task if not already selected (check by ID to avoid duplicates)
                if (!this.selectedTasks.some(sel => sel.id === task.id)) {
                    this.selectedTasks = [...this.selectedTasks, task];
                }
            } else {
                // Remove task by ID
                this.selectedTasks = this.selectedTasks.filter(sel => sel.id !== task.id);
            }
        }
    }
};
</script>

