<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{$t('TaskDetails')}}</h4>
                        <button type="button" class="close" v-on:click="CloseViewTaskDetails()">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                          <div class="col-md-12 p-0 float-left">
                             <div class="col-md-12 p-0 mb-3">
                                <div class="col-lg-12 mb-3 p-0">
                                    <div class="heading-border mt-2">
                                        <h5 class="h5">
                                        <span>{{ $t('Details') }}</span>                      
                                        </h5>
                                    </div>
                                </div>
                             </div>
                             <div class="row">
                                <div class="col-md-6 col-lg-4 detailsfix">
                                    <div class="form-group">
                                                <label><b>{{ title_name }} {{ 'Name' }} :</b> {{ task.title }}</label>
                                    </div>
                                </div>
                                <div class="col-md-6 col-lg-4 detailsfix">
                                    <div class="form-group">
                                    <label><b>{{title_name}} {{ $t('Description') }}:</b> {{ task.taskdescription }}</label>
                                    </div>
                                </div>  
                                <div class="col-md-6 col-lg-4 detailsfix">
                                    <div class="form-group">
                                    <label><b>{{ title_name }} {{ $t('Type') }}:</b> {{ task.type }}</label>
                                    </div>
                                </div>
                                <div class="col-md-6 col-lg-4 detailsfix" v-if=" task.type=='Task'">
                                    <div class="form-group">
                                    <label><b>{{ $t('ProjectName') }}:</b> {{ task.projectName }}</label>
                                    </div>
                                </div> 
                                <div class="col-md-6 col-lg-4 detailsfix">
                                    <div class="form-group">
                                    <label><b>{{ $t('EventPriority') }}:</b><span class="ml-1" :style="{ backgroundColor: task.colorCode }">{{ task.priority }}</span> </label>
                                    </div>
                                </div>
                                <div class="col-md-6 col-lg-4 detailsfix">
                                    <div class="form-group">
                                    <label><b>{{ $t('EventStartDate') }}:</b> {{  $d(new Date(task.date)) }}</label>
                                    </div>
                                </div>
                                <div class="col-md-6 col-lg-4 detailsfix">
                                    <div class="form-group">
                                    <label><b>{{ $t('EndDate') }}:</b> {{$d(new Date(task.dueDate)) }}</label>
                                    </div>
                                </div>    
                             </div>
                          </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
export default {
    props:{
        task:{
            type:Object
        }
    },
    data() {
        return {
            isLoading:false
        }
    },
    computed: {
        title_name() {
            if (this.task.type === 'Task') return 'Task';
            if (this.task.type === 'Project') return 'Project';
            if (this.task.type === 'FollowUp') return 'FollowUp';
            return '';
        }
    },
    mounted() {

    },
    created() {
        debugger
    },
    methods: {
        CloseViewTaskDetails: function () {
            var vm = this;
            vm.$emit("closeViewTaskDetails");
        },
    }
}
</script>