                                            <label class="cogfiglbl form-check form-check-inline">
                                                <div class="custom-control custom-radio custom-control-inline">
                                                    <input class="custom-control-input" name="resourceImpactBy"
                                                        id="rdoResignType" value="Resign" type="radio"
                                                        v-model="selectedImpactType" @change="onImpactTypeChange">
                                                    <label class="custom-control-label" for="rdoResignType"></label>
