                                                    </v-date-picker>

                                                </div>
                                            </div>
                                            <div class="col-12 col-md-6 float-left" id="leaveEndDate">
                                                <div class="input-group">
                                                    <v-date-picker v-bind:name="StartDateForSearch"
                                                        :minute-increment="5" class="timedate input-group"
                                                        v-model="RequestEndDate" :min-date="RequestStartDate">
                                                        <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                            <input placeholder="MM/DD/YYYY" class="form-control"
                                                                :value="inputValue" v-on="inputEvents" />

                                                            <div class="input-group-append" v-on:click="togglePopover">
                                                                <span class="input-group-text">
                                                                    <em class="fa fa-calendar"></em>
