                                <div class="col-lg-3" id="resignDate" v-else>
                                    <div class="form-group">
                                        <label class="mb-1">{{ $t('ResignDate') }}:</label>
                                        <div class="input-group">
                                            <v-date-picker v-bind:name="StartDateForSearch" :minute-increment="5"
                                                class="timedate input-group" v-model="ResignDate">
                                                <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                    <input placeholder="M/D/YYYY" class="form-control"
                                                        :value="inputValue" v-on="inputEvents" />

                                                    <div class="input-group-append" v-on:click="togglePopover">
                                                        <span class="input-group-text">
                                                            <em class="fa fa-calendar"></em>
                                                        </span>
                                                    </div>
                                                </template>
                                            </v-date-picker>
                                        </div>
                                    </div>
                                </div>
                                <div class="col-lg-2">
                                    <div class="form-group">
                                        <label class="mb-1">&nbsp;</label>
                                        <div class="row">
                                            <div class="col-12">
                                                <a title="Search" id="aGetResourceImpact" href="javascript:;"
                                                    @click="SearchGetResourceImpact"
                                                    class="btn btn-success mr-1 px-4 pb04" data-toggle-tooltip="tooltip"
                                                    data-original-title="Search"><em class="fa fa-search"></em></a>
                                                <a href="javascript:;" id="ancCancelRI" title="Clear"
                                                    @click="clearSearch"
                                                    class="btn btn-danger clearsearchtext px-4 pb04"
                                                    data-toggle-tooltip="tooltip" data-original-title="Clear"><em
                                                        class="fa fa-refresh"></em></a>
