                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        
        <!-- Resource Information Card -->
        <!-- <div v-if="resourceInfo" class="resource-info-card">
            <div class="resource-header">
                <div class="resource-name">{{ resourceInfo.name }}</div>
                <div :class="['status-badge', resourceInfo.status === 'Leave' ? 'status-leave' : 'status-resigned']">
                    {{ resourceInfo.status === 'Leave' ? 'On Leave' : 'Resigned' }}
                </div>
            </div>
            <div class="resource-details">
                <div class="detail-item">
                    <span class="detail-label">Department</span>
                    <span class="detail-value">{{ resourceInfo.department || 'N/A' }}</span>
                </div>
                <div class="detail-item">
                    <span class="detail-label">Role</span>
                    <span class="detail-value">{{ resourceInfo.role || 'N/A' }}</span>
                </div>
                <div class="detail-item">
                    <span class="detail-label">{{ selectedImpactType === 'Leave' ? 'Leave Period' : 'Resign Date' }}</span>
                    <span class="detail-value">{{ getDateRange() }}</span>
                </div>
                <div class="detail-item">
                    <span class="detail-label">Total Impact</span>
                   
                </div>
            </div>
        </div> -->
        
        <!-- Calendar View -->
        <div v-if="resourceData && resourceData.items && resourceData.items.length > 0" class="calendar-section">
            <ResourceImpactCalendar 
                :resourceData="resourceData"
                :initialView="activeView"
                @item-click="onItemClick"
                @view-changed="onViewChanged"
            />
        </div>
        
    
        <div v-if="taskList && taskList.length > 0" class="task-list-section">
            <ResourceImpactTaskList 
                :tasks="taskList"
                :projects="resourceData"
                :followUp="followUpData"
                @reassign-task="openReassignModal"
                @view-details="viewTaskDetails"
                @drag-start="onDragStart"
                @drag-end="onDragEnd"
            />
        </div>
        
       
        <ReassignTaskModal
            :show="showReassignModal"
            :task="selectedTask"
            :availableResources="availableResources"
            @close="closeReassignModal"
            @confirm="confirmReassignment"
        />

        <ViewTaskDetails v-if="IsViewTaskDetails" :task="TaskObj" @closeViewTaskDetails="closeViewTaskDetails"></ViewTaskDetails>
    </section>
</template>
<script>
import DataService from "../../../services/DataService";
import ResourceImpactCalendar from './ResourceImpactCalendar.vue';
import ResourceImpactTaskList from './ResourceImpactTaskList.vue';
import ReassignTaskModal from './ReassignTaskModal.vue';
import ViewTaskDetails from "./ViewTaskDetails.vue";

export default {
    name: 'ResourceImpact',
    components: {
        ResourceImpactCalendar,
        ResourceImpactTaskList,
        ReassignTaskModal,
        ViewTaskDetails
    },
    data() {
        return {
            isLoading:false,
            ResignDate: null,
            selectedTask:null,
            RequestStartDate: null,
            RequestEndDate: null,
            companyId: null,
            userId: null,
            UserData: [],
            isleaveStartDate: true,
            selectedImpactType: 'Leave',
            UserId: '',
            type: '',
            activeView:'Week',
            StartDateForSearch:'',
            resourceData:'',
            followUpData:'',
            taskList:[],
            IsViewTaskDetails:false,
            TaskObj:{},
            availableResources:[],
            showReassignModal:false,
            resourceInfo:[]
        }
    },
    created: function () {
        var ths = this;
        ths.userId = ths.GetUserInfo.ID;
        ths.companyId = ths.GetUserInfo.CompanyId;
        ths.GetUserList();
    },
    methods: {
        GetUserList: async function () {
            var ths = this;
            ths.UserData=[];
            var url = `projectIds=&userTypes=&isActive=1&isIncludedLoginUserId=true&moduleName=Project&ticketId=0`;
            await DataService.GetUserList(url).then((response) => {              
                if (response.status == 200) {
                    if (response.data.length > 0) {                       
                        response.data.forEach((element) => {
                            var obj = {
                                UserId: element.UserId,
                                UserName: element.UserName
                            }
                            ths.UserData.push(obj)
                        })
                    }
                }
            })
        },
        onImpactTypeChange: function () {
            if (this.selectedImpactType === 'Leave') {
                this.isleaveStartDate = true;
            } else if (this.selectedImpactType === 'Resign') {
                this.isleaveStartDate = false;
            }
        },
        formatDate(date,format) {
            if(format)
                    {
            const d = new Date(date);
            const month = (d.getMonth() + 1).toString().padStart(2, '0');
            const day = d.getDate().toString().padStart(2, '0');
            const year = d.getFullYear();
            return `${year}-${month}-${day}`;
          }
            else{
                const d = new Date(date);
            const month = (d.getMonth() + 1).toString().padStart(2, '0');
            const day = d.getDate().toString().padStart(2, '0');
            const year = d.getFullYear();
            return `${month}/${day}/${year}`;
            }
        },
        SearchGetResourceImpact: function () { 
            var ths = this;
            ths.isLoading = true;            
            if (ths.selectedImpactType === 'Leave' && ths.UserId != null && ths.RequestStartDate != null && ths.RequestEndDate != null) {
                if (ths.type == 'Res' && ths.selectedImpactType === 'Leave') {
                    // Handle resource reassignment case
                } 
                else {                                        
                    var RequestStartDate = ths.formatDate(ths.RequestStartDate,true);
                    var RequestEndDate = ths.formatDate(ths.RequestEndDate,true);
                    // var url = `userid=${ths.UserId}&companyid=${ths.companyId}&type=${ths.selectedImpactType}&startDate=${RequestStartDate}&endDate=${RequestEndDate}`;                  
                    var url = `userid=${ths.UserId}&companyid=${ths.companyId}&type=${ths.selectedImpactType}&startDate=${RequestStartDate}&endDate=${RequestEndDate}`;
                    
                    DataService.GeTResourceImpactJson(url).then((response) => {                        
                        ths.isLoading = false;
                        if (response.data.status == "Success") {
                            if (response.data.result.DATA.length > 0) {                                
                                ths.processResourceImpactData(response.data.result.DATA,response.data.result.FOLLOWUP_DATA);
                            } else {                                
                                ths.ShowAlert(ths.$t("No_Record_Found"),'failure',true,ths.$t('Alert'));
                                ths.resourceData = null;
                                ths.taskList = [];
                            }
                        }
                    }).catch((error) => {
                        ths.isLoading = false;
                        ths.ShowAlert(ths.$t("Error_Loading_Data"),'failure',true,ths.$t('Alert'));
                    });
                }
            } 
            else if (ths.selectedImpactType === 'Resign' && ths.UserId != null && ths.ResignDate != null) {
                // Handle resign case                
                var ResignDate = ths.formatDate(ths.ResignDate);
                var url = `userid=${ths.UserId}&companyid=${ths.companyId}&type=${ths.selectedImpactType}&startDate=${RequestStartDate}&endDate=${RequestEndDate}`;
                DataService.GeTResourceImpactJson(url).then((response) => {
                    ths.isLoading = false;                    
                    if (response.status == 200) {                        
                        if (response.data.result.DATA.length > 0) {
                            ths.processResourceImpactData(response.data.result.DATA,response.data.result.FOLLOWUP_DATA);
                        } else {
                            ths.ShowAlert(ths.$t("No_Record_Found"),'failure',true,ths.$t('Alert'));
                            ths.resourceData = null;
                            ths.taskList = [];
                        }
                    }
                }).catch((error) => {
                    ths.isLoading = false;
                    ths.ShowAlert(ths.$t("Error_Loading_Data"),'failure',true,ths.$t('Alert'));
                });
            } 
            else {
                ths.isLoading = false;
                ths.ShowAlert(ths.$t("Please_Fill_All_Fields"),'warning',true,ths.$t('Alert'));
            }
        },
        processResourceImpactData(data,FollowUp) {
            const items = [];
            const tasks = [];       
            const Projects=[];     
            this.followUpData= FollowUp.length > 0  ? FollowUp :[];
            if (data && data.length > 0) {
                data.forEach(project => {
                    if (project.listTask && project.listTask !="[]") {
                        var taskList=JSON.parse(project.listTask);
                        taskList.forEach(task => {
                            const item = {
                                id: task.Task_Id || task.TASK_ID,
                                projectId:project.PROJECT_ID,
                                title: task.Task_Name || task.TASK_NAME || 'Task',
                                type: 'Task',
                                date: this.parseDate(task.PLANNED_START_DATE || task.PLANNED_START_DATE),
                                startTime: this.getTimeFromDate(task.PLANNED_START_DATE || task.PLANNED_START_DATE),
                                endTime: this.getTimeFromDate(task.PLANNED_END_DATE || task.PLANNED_END_DATE),
                                projectName: project.ProjectName || project.PROJECT_NAME,
                                priority: task.PRIORITY_NAME,
                                dueDate: task.EndDate || task.PLANNED_END_DATE,
                                taskdescription:task.TASK_DESCRIPTION,
                                colorCode:task.COLOR_CODE
                            };
                            items.push(item);                            
                            tasks.push({
                                id: item.id,
                                title: item.title,
                                type: 'Task',
                                projectName: item.projectName,
                                projectId:item.projectId,
                                priority: item.priority,
                                dueDate: item.dueDate,
                                date: item.date,
                                taskdescription:item.taskdescription,
                                colorCode:item.colorCode
                            });                           
                        });
                    }                   
                    // Add project as item
                    if (project.PLANNED_START_DATE || project.PLANNED_END_DATE) {
                    
                        Projects.push({
                            id: `project-${project.PROJECT_ID || project.PROJECT_ID}`,
                            title: project.PROJECT_NAME || project.PROJECT_NAME,
                            type: 'Project',
                            date: this.parseDate(project.PLANNED_START_DATE || project.PLANNED_START_DATE),
                            dueDate:this.parseDate(project.PLANNED_END_DATE || project.PLANNED_END_DATE),
                            priority:project.PRIORITY_NAME,
                            colorCode:project.COLOR_CODE,
                            taskdescription:project.PROJECT_DESCRIPTION,
                            startTime: 9,
                            endTime: 17
                        });

                    }
                   
                });
            }    
            debugger        
            this.resourceData = {
                items: Projects
            };            
            this.taskList = tasks;            
            // Set resource info
            // const selectedUser = this.UserData.find(u => u.UserId == this.UserId);
            // if (selectedUser) {
            //     this.resourceInfo = {
            //         name: selectedUser.UserName,
            //         status: this.selectedImpactType,
            //         department: selectedUser.Department || 'N/A',
            //         role: selectedUser.Role || 'N/A'
            //     };
            // }            
            // Get available resources for reassignment
            //this.getAvailableResources();
        },
        parseDate(dateValue) {
            if (!dateValue) return null;
            if (typeof dateValue === 'number') {
                return new Date(dateValue.toString().length === 10 ? dateValue * 1000 : dateValue);
            }
            return new Date(dateValue);
        },
        getTimeFromDate(dateValue) {
            if (!dateValue) return 9; // Default to 9 AM
            const date = this.parseDate(dateValue);
            return date.getHours() + (date.getMinutes() / 60);
        },
        getDateRange() {
            if (this.selectedImpactType === 'Leave') {
                if (this.RequestStartDate && this.RequestEndDate) {
                    return `${this.formatDate(this.RequestStartDate)} - ${this.formatDate(this.RequestEndDate)}`;
                }
            } else {
                if (this.ResignDate) {
                    return this.formatDate(this.ResignDate);
                }
            }
            return 'N/A';
        },
        // get impactSummary() {
        //     const projectCount = this.resourceData?.items?.filter(i => i.type === 'Project').length || 0;
        //     const taskCount = this.taskList.length;
        //     return `${projectCount} Projects, ${taskCount} Tasks`;
        // },
        getAvailableResources() {
            // Get list of available resources (excluding the current user)
            this.availableResources = this.UserData
                .filter(user => user.UserId != this.UserId)
                .map(user => ({
                    id: user.UserId,
                    name: user.UserName,
                    role: user.Role || 'Team Member',
                    department: user.Department || 'N/A'
                }));
        },
        onItemClick(item) {
            console.log('Item clicked:', item);
        },
        onViewChanged(view) {
            this.activeView = view;
        },
        openReassignModal(task) {
            this.selectedTask = task;
            this.showReassignModal = true;
        },
        closeReassignModal() {

            this.showReassignModal = false;
            this.selectedTask = null;
        },
        confirmReassignment(data) {
            const { task, resource } = data;
            const reassignData = {
                taskId: task.id,
                newResourceId: resource.id,
                oldResourceId: this.UserId
            };            
            this.ShowAlert(`Task "${task.title}" has been reassigned to ${resource.name}`, 'success', true, this.$t('Alert'));
            this.SearchGetResourceImpact();
        },
        viewTaskDetails(task) {
            debugger
            this.TaskObj = task;
            this.IsViewTaskDetails = true;            
        },
        closeViewTaskDetails(){
            this.IsViewTaskDetails = false;            
        },
        onDragStart(task) {
        },
        onDragEnd() {
        },
        clearSearch() {
            this.UserId = null;
            this.RequestStartDate = null;
            this.RequestEndDate = null;
            this.ResignDate = null;
            this.resourceData = null;
            this.resourceInfo = null;
            this.taskList = [];
            this.showReassignModal = false;
            this.selectedTask = null;
        }
    }
}
</script>


