<template>
    <div class="quarter-view">
        <div class="quarter-grid">
            <div 
                v-for="month in quarterMonths" 
                :key="month.month"
                class="quarter-month">
                <div class="month-header">
                    <h4>{{ month.name }}</h4>
                    <div class="month-year">{{ month.year }}</div>
                </div>
                <div class="month-calendar">
                    <div class="month-day-names">
                        <div v-for="dayName in dayNames" :key="dayName" class="day-name">
                            {{ dayName }}
                        </div>
                    </div>
                    <div class="month-days-grid">
                        <div 
                            v-for="(day, index) in month.days" 
                            :key="index"
                            class="quarter-day-cell"
                            :class="{ 
                                'other-month': !day.isCurrentMonth,
                                'today': day.isToday
                            }">
                            <div class="day-number">{{ day.date }}</div>
                            <div class="day-items">
                                <div 
                                    v-for="item in getItemsForDay(day.fullDate)"
                                    :key="item.id"
                                    :class="['calendar-item', getItemTypeClass(item.type)]"
                                    @click="onItemClick(item)"
                                    :title="item.title">
                                    <div class="item-title">{{ item.title }}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import moment from 'moment';

export default {
    name: 'ResourceImpactQuarterView',
    props: {
        currentDate: {
            type: Date,
            required: true
        },
        resourceData: {
            type: Object,
            default: () => ({})
        }
    },
    data() {
        return {
            dayNames: ['S', 'M', 'T', 'W', 'T', 'F', 'S']
        };
    },
    computed: {
        quarterMonths() {
            const quarter = Math.floor(moment(this.currentDate).month() / 3);
            const year = moment(this.currentDate).year();
            const months = [];
            const today = moment();
            
            for (let i = 0; i < 3; i++) {
                const monthIndex = quarter * 3 + i;
                const monthDate = moment().year(year).month(monthIndex).date(1);
                const startOfMonth = moment(monthDate).startOf('month');
                const endOfMonth = moment(monthDate).endOf('month');
                const startOfCalendar = moment(startOfMonth).startOf('week');
                const endOfCalendar = moment(endOfMonth).endOf('week');
                
                const days = [];
                let currentDay = moment(startOfCalendar);
                
                while (currentDay.isSameOrBefore(endOfCalendar)) {
                    days.push({
                        date: currentDay.format('D'),
                        fullDate: currentDay.toDate(),
                        isCurrentMonth: currentDay.isSame(monthDate, 'month'),
                        isToday: currentDay.isSame(today, 'day')
                    });
                    currentDay.add(1, 'day');
                }
                
                months.push({
                    month: monthIndex,
                    name: monthDate.format('MMMM'),
                    year: year,
                    days: days
                });
            }
            
            return months;
        }
    },
    methods: {
        getItemsForDay(date) {
            if (!this.resourceData.items) return [];
            
            return this.resourceData.items.filter(item => {
                if (!item.date) return false;
                return moment(item.date).isSame(moment(date), 'day');
            }).slice(0, 2); // Show max 2 items per day in quarter view
        },
        getItemTypeClass(type) {
            const typeMap = {
                'Project': 'item-project',
                'Task': 'item-task',
                'Todo': 'item-todo',
                'Meeting': 'item-meeting',
                'FollowUp': 'item-followup'
            };
            return typeMap[type] || 'item-default';
        },
        onItemClick(item) {
            this.$emit('item-click', item);
        }
    }
};
</script>

<style scoped>
.quarter-view {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.quarter-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
}

.quarter-month {
    background: white;
    border-radius: 8px;
    padding: 15px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.month-header {
    text-align: center;
    margin-bottom: 15px;
    padding-bottom: 10px;
    border-bottom: 2px solid #e9ecef;
    background: #c5c5c5;
    padding-top: 15px;
}

.month-header h4 {
    margin: 0;
    font-size: 16px;
    font-weight: 600;
    color: #212529;
}

.month-year {
    font-size: 12px;
    color: #6c757d;
    margin-top: 4px;
}

.month-day-names {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 2px;
    margin-bottom: 5px;
}

.day-name {
    text-align: center;
    font-size: 11px;
    font-weight: 600;
    color: #6c757d;
    padding: 4px;
}

.month-days-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 2px;
}

.quarter-day-cell {
    background: #f8f9fa;
    padding: 4px;
    min-height: 60px;
    border-radius: 4px;
    position: relative;
}

.quarter-day-cell.other-month {
    opacity: 0.4;
}

.quarter-day-cell.today {
    background: #fff3cd;
    border: 2px solid #4361ee;
}

.day-number {
    font-size: 11px;
    font-weight: 600;
    margin-bottom: 2px;
    color: #212529;
}

.quarter-day-cell.today .day-number {
    color: #4361ee;
}

.day-items {
    display: flex;
    flex-direction: column;
    gap: 1px;
}

.calendar-item {
    border-radius: 2px;
    padding: 2px 4px;
    font-size: 9px;
    color: white;
    cursor: pointer;
    transition: all 0.2s ease;
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
}

.calendar-item:hover {
    transform: scale(1.05);
    z-index: 10;
}

.item-project {
    background: #4361ee;
}

.item-task {
    background: #f72585;
}

.item-todo {
    background: #4cc9f0;
}

.item-meeting {
    background: #06d6a0;
}

.item-followup {
    background: #ffbe0b;
    color: #212529;
}

.item-default {
    background: #6c757d;
}

.item-title {
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@media (max-width: 1200px) {
    .quarter-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 768px) {
    .month-days-grid {
        grid-template-columns: 1fr;
    }
    
    .quarter-day-cell {
        min-height: 50px;
    }
}
</style>

