<template>
    <div>
        <loader :is-visible="isLoading"></loader>
        <div class="my-popups" v-if="show">
            <div  class="modal d-block">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                       
                            <div class="modal-header theme-primary partition-full  d-flex">
                                <h4 class="modal-title">Reassign Task</h4>
                                <button type="button" class="close"  @click="closeModal">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>                        
                            </div>
                        
                        <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="reassignForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="confirmReassignment">
                        </dynamic-form>
                    </div>
                    </div>
                   
                </div>
            </div>
        </div>
</div>
</template>

<script>
import { Array } from 'core-js';
import DataService from '../../../services/DataService';
export default {
    name: 'ReassignTaskModal',
    props: { 
        show: {
            type: Boolean,
            default: false
        },       
        task: {
            type: Array,
            default: null
        },
        availableResources: {
            type: Array,
            default: () => []
        }
    },
    data() {
        return {
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            selectedResource: '',
            isLoading:false,
            selectuser:0,
            userData:[],
             FormSchema: [               
            {
                layoutType: "single",
                Data: [
                    {
                        astype: "SelectField",                                                
                        label: this.$t('Team Memeber'),
                        name: "selectMemeber",
                        value: "", 
                        config: {
                            options: []
                        },                           
                        placeholder: this.$t('Select Memeber'),
                        validationRules: { "required": true, max: 100 },
                    } 
                ]
                            }
                            
                        ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.closeModal,
                },
            ],
        };
    },
    watch: {
        
        show(newVal) {
            debugger 
            if (!newVal) {
                this.selectedResource = null;
            }
           else
           {
            this.GetUsers();
           }
        },
        task() {
            this.selectedResource = null;
        }
    },
    methods: {
        GetUsers : function (){ 
          var vm=this; 
          vm.isLoading=true;      
          vm.FormSchema[0].Data[0].config.options=[];
            var url = `id=${vm.task[0].projectId}&moduleName=PROJECT&type=PROJECT_USERS&search=&refId=`;
            DataService.GetDDLData(url).then((response) => {
                if (response.status == 200) {
                    if (response.data.DATA != undefined || response.data.DATA != null) {
                        if (response.data.DATA.length > 0) {
                            response.data.DATA.forEach(element => {
                                var obj = {
                                    value: element.value,
                                    name: element.name
                                }
                                                                
                                vm.FormSchema[0].Data[0].config.options.push(obj);
                              
                            });
                            vm.$refs.reassignForm.UpdateKeyValue(); 
                        }
                        
                    }
                }
                vm.isLoading=false;
            });
        }, 
        closeModal()
        {
            this.$parent.showReassignModal=false;
        },
        confirmReassignment :async function  () {        
            debugger 
            var vm = this;          
            vm.isLoading=true;
            var ids=vm.task.map(u=>u.id).join(',');        
            var url=`UserId=${vm.FormSchema[0].Data[0].value}&TaskId=${ids}`           
             DataService.AddMemberToTask(url).then(function (response) {
                vm.isLoading=false;
                if(response && response.data.status == "Success"){    
                    vm.ShowAlert("Add Member Task Successfully!", "success", true, vm.$t('Alert'));
                    vm.$parent.IsAssignedUserShow = false;
                        
                }else{
                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                }
            })

        },
        closeModal() {
            this.$emit('close');
        },
        selectResource(resource) {
            this.selectedResource = resource;
        },
        getInitials(name) {
            if (!name) return '';
            const parts = name.split(' ');
            if (parts.length >= 2) {
                return (parts[0][0] + parts[1][0]).toUpperCase();
            }
            return name.substring(0, 2).toUpperCase();
        },
        onDragOver(event) {
            event.preventDefault();
            event.currentTarget.classList.add('drag-over');
        },
        onDrop(event, resource) {
            event.preventDefault();
            event.currentTarget.classList.remove('drag-over');
            
            const taskId = event.dataTransfer.getData('text/plain');
            if (taskId && this.task && this.task.id === taskId) {
                this.selectResource(resource);
                this.confirmReassignment();
            }
        },
        // confirmReassignment() {
        //     if (!this.selectedResource || !this.task) {
        //         return;
        //     }
            
        //     this.$emit('confirm', {
        //         task: this.task,
        //         resource: this.selectedResource
        //     });
            
        //     this.closeModal();
        // }
    }
};
</script>

<style scoped>



.resources-list {
    gap: 15px;
    margin-top: 15px;
}

.resource-option {
    border: 2px solid #e9ecef;
    border-radius: 8px;
    padding: 15px;
    text-align: center;
    cursor: pointer;
    transition: all 0.3s ease;
    background: white;
}

.resource-option:hover {
    border-color: #4361ee;
    transform: translateY(-2px);
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
}

.resource-option.selected {
    border-color: #4361ee;
    background: rgba(67, 97, 238, 0.05);
}

.resource-option.drag-over {
    border-color: #4361ee;
    background: rgba(67, 97, 238, 0.1);
    transform: scale(1.05);
}

.resource-avatar {
    width: 50px;
    height: 50px;
    border-radius: 50%;
    background: #4361ee;
    display: flex;
    align-items: center;
    justify-content: center;
    color: white;
    font-weight: bold;
    margin: 0 auto 10px;
    font-size: 18px;
}

.resource-name {
    font-weight: 600;
    margin-bottom: 4px;
    color: #212529;
}

.resource-role {
    font-size: 12px;
    color: #6c757d;
}
.btn {
    padding: 10px 20px;
    border: none;
    border-radius: 8px;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    transition: all 0.3s ease;
}

.btn-primary {
    background: #4361ee;
    color: white;
}

.btn-primary:hover:not(:disabled) {
    background: #3f37c9;
}

.btn-primary:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-outline {
    background: transparent;
    border: 1px solid #4361ee;
    color: #4361ee;
}

.btn-outline:hover {
    background: rgba(67, 97, 238, 0.1);
}

@media (max-width: 768px) {
    .resources-list {
        grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
    }
}
</style>